export default `*{box-sizing:border-box}html,body{margin:0;padding:0;background:#020617;color:#e5e7eb;font-family:Inter,system-ui,sans-serif;height:100%;overflow:hidden}::-webkit-scrollbar{width:8px;height:8px}::-webkit-scrollbar-thumb{background:#465a9673;border-radius:6px}::-webkit-scrollbar-track{background:#0a0f1e66}.panel{background:#0f172ae6;border:1px solid rgba(30,64,175,.7);border-radius:10px}.panel-header{padding:.75rem 1rem;border-bottom:1px solid rgba(51,65,85,.9);display:flex;justify-content:space-between;align-items:center}.button-base,.button-danger,.button-primary{border-radius:999px;padding:6px 12px;font-size:12px;border:1px solid transparent;background:transparent;color:#e5e7eb;cursor:pointer;transition:background .12s ease,border-color .12s ease,transform 80ms ease,filter .12s ease}.button-base:hover,.button-danger:hover,.button-primary:hover{transform:translateY(-1px);filter:brightness(1.05)}.button-base:disabled,.button-danger:disabled,.button-primary:disabled{opacity:.6;cursor:default;transform:none;filter:none}.button-base,.button-danger,.button-primary{border:1px solid rgba(148,163,184,.5);background:#0f172ae6;color:#e5e7eb;cursor:pointer;transition:transform .12s ease,opacity .12s ease}.button-base:hover,.button-danger:hover,.button-primary:hover{transform:translateY(-1px);opacity:1}.button-primary{background:#2563eb;border-color:#2563eb2e;color:#fff}.button-primary:hover{filter:brightness(1.05)}.button-danger{background:#ef4444;border-color:#b91c1c;color:#fff}.table{width:100%;border-collapse:collapse;font-size:.85rem}.table thead{background:#0a1428e6;position:sticky;top:0;z-index:5}.table thead th{padding:.55rem .65rem;font-weight:600;font-size:.75rem;text-align:left;border-bottom:1px solid rgba(30,64,175,.7);color:#ffffffb3;-webkit-backdrop-filter:blur(8px);backdrop-filter:blur(8px)}.table thead th .col-meta{margin-left:.3rem;border-radius:999px;padding:.05rem .35rem;background:#0f192dd9;border:1px solid rgba(148,163,184,.5);font-size:.7rem;color:#9ca3af}.table tbody tr{transition:background .12s ease,transform 80ms ease}.table tbody tr:nth-child(odd){background:#0c142df2}.table tbody tr:nth-child(2n){background:#101937f2}.table tbody tr:hover{background:#1e293b;transform:translateY(-1px);box-shadow:0 2px 6px #00000059}.table td{padding:.45rem .65rem;border-bottom:1px solid rgba(30,40,70,.35);vertical-align:top}.table td code{font-family:ui-monospace,SF Mono,Consolas,monospace;font-size:.78rem;color:#ffffffb3;white-space:nowrap;text-overflow:ellipsis;overflow:hidden;display:block}.pk-header{background:#ffe69640}.pk-cell{background:#ffe69659!important;border-right:2px solid #e0b132;font-weight:600}.pk-tag{color:#b87500!important;font-weight:700}.sidebar-group{background:#19233c59;border-radius:999px;border:1px solid rgba(70,90,140,.55);padding:.35rem .65rem;display:flex;align-items:center;gap:.4rem;font-size:.78rem;cursor:pointer;color:#e5e7eb;transition:background .12s ease}.sidebar-group:hover{background:#283c6e73}.sidebar-group .chevron{transition:transform .15s ease}.sidebar-group .chevron.collapsed{transform:rotate(-90deg)}.sidebar-item{border-radius:.55rem;background:#0f1932a6;border:1px solid rgba(40,60,110,.4);padding:.55rem .7rem;display:flex;flex-direction:column;gap:.15rem;cursor:pointer;opacity:.9;transition:.12s ease}.sidebar-item:hover{background:#141e46bf;transform:translateY(-1px);box-shadow:0 2px 6px #00000059;opacity:1}.sidebar-item.active{background:#2563eb;border-color:#2563eb2e;color:#fff;opacity:1}.input{padding:.35rem .55rem;border-radius:999px;background:#0f172ae6;border:1px solid rgba(148,163,184,.5);color:#e5e7eb;font-size:.85rem}.input:focus{outline:none;border-color:#2563eb}.flex{display:flex}.flex-col{display:flex;flex-direction:column}.flex-between{display:flex;justify-content:space-between;align-items:center}.gap-sm{gap:.25rem}.gap-md{gap:.5rem}.gap-lg{gap:1rem}.w-full{width:100%}.h-full{height:100%}.list,.sublist{list-style:none;margin:0;padding:0;display:flex;flex-direction:column;gap:.35rem}.sublist{margin-left:.75rem;padding-left:.25rem;border-left:1px solid rgba(80,100,150,.35)}
`;